from __future__ import annotations


def management_report_dashboard_html() -> str:
    return r'''<!doctype html>
<html lang="ru">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Сводка руководителя</title>
<style>
:root{color-scheme:dark;--bg:#07101d;--panel:#101b2d;--panel2:#142238;--line:#283956;--text:#eef5ff;--muted:#91a3bd;--accent:#6d8cff;--ok:#35d08a;--warn:#ffbd4a;--bad:#ff5d78}
*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 80% 0,rgba(109,140,255,.14),transparent 30%),var(--bg);color:var(--text);font:14px/1.5 Inter,Segoe UI,Arial,sans-serif}main{max-width:1380px;margin:auto;padding:24px 28px 80px}.hero{display:flex;justify-content:space-between;gap:20px;align-items:flex-start;margin-bottom:18px}.hero h1{margin:0;font-size:28px}.hero p{color:var(--muted);max-width:820px;margin:7px 0}.actions{display:flex;gap:8px;flex-wrap:wrap}button,a.btn{border:1px solid var(--line);background:var(--panel);color:var(--text);padding:9px 12px;border-radius:10px;cursor:pointer;text-decoration:none}.primary{background:linear-gradient(135deg,#496ee8,#7657de);border:0}.status{color:var(--muted);font-size:12px}.summary{display:grid;grid-template-columns:1.35fr repeat(3,1fr);gap:12px;margin-bottom:14px}.card,.section{background:linear-gradient(180deg,rgba(20,34,56,.97),rgba(12,23,39,.97));border:1px solid var(--line);border-radius:15px;padding:18px}.section{margin-bottom:14px}.hero-card{display:flex;gap:18px;align-items:center}.score{font-size:52px;font-weight:800;line-height:1}.grade{font-size:16px;color:var(--muted)}.metric .label{color:var(--muted);font-size:12px}.metric .value{font-size:28px;font-weight:750;margin:6px 0}.metric .note{font-size:12px;color:var(--muted)}.bad{color:var(--bad)}.warn{color:var(--warn)}.ok{color:var(--ok)}.layout{display:grid;grid-template-columns:1.25fr .75fr;gap:14px}.section h2{margin:0 0 13px;font-size:17px}.issue{display:grid;grid-template-columns:36px 1fr;gap:11px;padding:13px 0;border-bottom:1px solid rgba(40,57,86,.75)}.issue:last-child{border-bottom:0}.rank{width:30px;height:30px;border-radius:9px;display:grid;place-items:center;background:rgba(255,93,120,.14);color:var(--bad);font-weight:800}.issue h3{margin:0 0 3px;font-size:14px}.issue p{margin:3px 0;color:var(--muted)}.decision{padding:12px;border-radius:11px;background:rgba(109,140,255,.09);border:1px solid rgba(109,140,255,.28);margin:9px 0}.decision b{display:block;margin-bottom:4px}.roi{display:grid;grid-template-columns:1fr 1fr;gap:10px}.roi .box{padding:14px;border-radius:12px;background:rgba(53,208,138,.08);border:1px solid rgba(53,208,138,.25)}.roi strong{font-size:24px;color:var(--ok)}.row{display:grid;grid-template-columns:1fr auto;gap:10px;padding:9px 0;border-bottom:1px solid rgba(40,57,86,.65)}.bar{height:6px;background:#1b2b44;border-radius:99px;overflow:hidden;margin-top:6px}.bar i{display:block;height:100%;background:linear-gradient(90deg,#ff5d78,#ffbd4a,#35d08a)}details{background:rgba(16,27,45,.72);border:1px solid var(--line);border-radius:14px;padding:14px;margin-top:14px}summary{cursor:pointer;font-weight:700}.evidence{margin:8px 0;padding:10px;border:1px solid rgba(40,57,86,.65);border-radius:10px}.empty{color:var(--muted);padding:18px}.notice{padding:10px 12px;border:1px solid rgba(255,189,74,.35);background:rgba(255,189,74,.08);border-radius:10px;margin-bottom:12px}.history table{width:100%;border-collapse:collapse}.history th,.history td{padding:10px;border-bottom:1px solid var(--line);text-align:left}@media(max-width:1050px){.summary{grid-template-columns:1fr 1fr}.layout{grid-template-columns:1fr}}@media(max-width:650px){main{padding:18px}.hero{display:block}.summary{grid-template-columns:1fr}.roi{grid-template-columns:1fr}}
</style>
</head>
<body><main>
<div class="hero"><div><h1>Сводка руководителя</h1><p>Готовая управленческая картина без технических терминов. Последний подтверждённый снимок показывается сразу, обновление выполняется в фоне.</p><div class="status" id="updated">Загрузка последнего подтверждённого снимка…</div></div><div class="actions"><button id="refresh">Обновить данные</button><a class="btn" href="/executive-intelligence" target="_blank">Открыть аналитику</a></div></div>
<div id="notice"></div><div id="content"><div class="section empty">Загрузка данных…</div></div>
<details><summary>Подробный отчёт и история</summary><div class="actions" style="margin:14px 0"><button id="generate">Сформировать подробный PDF</button><a class="btn" id="latestPdf">Последний PDF</a></div><div class="history"><table><thead><tr><th>Дата</th><th>Режим</th><th>Действие</th></tr></thead><tbody id="history"></tbody></table></div><div class="status" id="reportStatus"></div></details>
</main><script>
const $=s=>document.querySelector(s);
function esc(v){const d=document.createElement('div');d.textContent=v??'';return d.innerHTML}
function money(v){return v==null?'не рассчитано':new Intl.NumberFormat('ru-RU').format(Math.round(v))+' ₸'}
function num(v){return new Intl.NumberFormat('ru-RU',{maximumFractionDigits:1}).format(Number(v||0))}
function severity(v){return v==='critical'?'Критично':v==='high'?'Высокий риск':v==='medium'?'Требует внимания':'Наблюдение'}
function statusName(v){return v==='implemented'?'Реализовано':v==='partial'?'Частично реализовано':v==='missing'?'Подтверждений не найдено':'Требует проверки'}
function decisions(d){const out=[];const risks=d.risks||[];const ref=(d.reference_audit||{}).critical_gaps||[];if(Number((d.source_summary||{}).without_deadline)>0)out.push(['Утвердить обязательные сроки задач','Сделать крайний срок обязательным для рабочих шаблонов и включить эскалацию просрочки.']);if(risks.some(x=>String(x.title||'').includes('CRM')))out.push(['Утвердить единые правила ведения CRM','Закрепить обязательные поля, следующее действие и контроль сделок без активности.']);if(ref.length)out.push(['Утвердить приоритет устранения цифровых разрывов','Начать с обязательных возможностей с высокой уверенностью и максимальным влиянием на процессы.']);return out.slice(0,3)}
function evidenceHtml(x){const audit=x.evidence_audit||{},sources=audit.checked_sources||[],method=x.methodology||{};return '<details><summary>Почему система так решила</summary><p>'+esc(audit.rationale||'Вывод сформирован по доступным системным данным.')+'</p>'+sources.map(s=>'<div class="evidence"><b>'+esc(s.title||s.id)+'</b><br><span class="status">'+(s.available?(s.positive?'Найдено подтверждение':'Проверено, подтверждений не найдено'):'Источник недоступен')+'</span></div>').join('')+(method.objective?'<p><b>Целевое состояние:</b> '+esc(method.objective)+'</p>':'')+(method.recommendation?'<p><b>Рекомендация:</b> '+esc(method.recommendation)+'</p>':'')+'</details>'}
function render(d){
 const maturity=d.digital_maturity||{},src=d.source_summary||{},roi=d.roi||{},risks=(d.risks||[]).slice(0,5),deps=(d.department_rating||[]).filter(x=>Number(x.open||0)>=3||Number(x.score||0)<70).slice(0,5),dims=Object.values(d.dimensions||{}),dec=decisions(d),ref=d.reference_audit||{},refSummary=ref.summary||{},refGaps=(ref.critical_gaps||[]).filter(x=>x.required!==false).slice(0,6);
 let html='<div class="summary"><div class="card hero-card"><div><div class="score">'+esc(num(maturity.score))+'</div><div class="grade">из 100 · '+esc(maturity.level||'нет оценки')+' · '+esc(maturity.grade||'')+'</div></div><div><b>Состояние компании</b><p class="'+(Number(maturity.score)<55?'bad':Number(maturity.score)<70?'warn':'ok')+'">'+(Number(maturity.score)<55?'Требует срочного внимания':Number(maturity.score)<70?'Есть существенные слабые места':'В целом управляемо')+'</p></div></div><div class="card metric"><div class="label">Просрочка</div><div class="value bad">'+esc(num(src.overdue_rate))+'%</div><div class="note">доля открытых задач</div></div><div class="card metric"><div class="label">Без срока</div><div class="value warn">'+esc(src.without_deadline||0)+'</div><div class="note">задач невозможно контролировать по срокам</div></div><div class="card metric"><div class="label">Сотрудники в риске</div><div class="value bad">'+esc(src.employees_at_risk||0)+'</div><div class="note">нужна проверка нагрузки</div></div></div>';
 html+='<section class="section"><h2>Сравнение с эталонной моделью</h2><div class="summary" style="grid-template-columns:1.4fr 1fr 1fr 1fr"><div class="card metric"><div class="label">Профиль</div><div class="value" style="font-size:18px">'+esc((ref.profile||{}).title||'Не выбран')+'</div></div><div class="card metric"><div class="label">Покрытие</div><div class="value '+(Number(ref.coverage)<50?'bad':Number(ref.coverage)<75?'warn':'ok')+'">'+esc(num(ref.coverage))+'%</div></div><div class="card metric"><div class="label">Не подтверждено</div><div class="value bad">'+esc(refSummary.missing||0)+'</div></div><div class="card metric"><div class="label">Требует проверки</div><div class="value warn">'+esc(refSummary.unknown||0)+'</div></div></div>'+(refGaps.length?refGaps.map((x,i)=>'<div class="issue"><div class="rank">'+(i+1)+'</div><div><h3>'+esc(x.title)+'</h3><p><b class="bad">'+esc(statusName(x.status))+'</b> · '+esc(x.domain||'')+' · уверенность '+Math.round(Number(x.confidence||0)*100)+'%</p>'+evidenceHtml(x)+'</div></div>').join(''):'<div class="empty">Критичных обязательных разрывов не выявлено.</div>')+'</section>';
 html+='<div class="layout"><div><section class="section"><h2>Что требует внимания сейчас</h2>'+(risks.length?risks.map((r,i)=>'<div class="issue"><div class="rank">'+(i+1)+'</div><div><h3>'+esc(r.title)+'</h3><p><b>'+esc(severity(r.severity))+':</b> '+esc(r.fact||'')+'</p><p>Последствие: '+esc(r.impact||'')+'</p></div></div>').join(''):'<div class="empty">Критичных рисков не выявлено.</div>')+'</section><section class="section"><h2>Что необходимо решить руководству</h2>'+(dec.length?dec.map(x=>'<div class="decision"><b>'+esc(x[0])+'</b><span>'+esc(x[1])+'</span></div>').join(''):'<div class="empty">Отдельных решений руководства сейчас не требуется.</div>')+'</section></div><div><section class="section"><h2>Ожидаемый эффект</h2><div class="roi"><div class="box"><span>Экономия времени</span><br><strong>'+esc(num(roi.total_annual_hours))+'</strong><br><small>часов в год</small></div><div class="box"><span>Экономический эффект</span><br><strong>'+esc(money(roi.total_annual_saving_kzt))+'</strong><br><small>ориентир в год</small></div></div></section><section class="section"><h2>Подразделения, требующие внимания</h2>'+(deps.length?deps.map(x=>'<div class="row"><div>'+esc(x.name)+'<div class="bar"><i style="width:'+Math.max(0,Math.min(100,x.score||0))+'%"></i></div></div><b class="'+(x.score<55?'bad':x.score<70?'warn':'ok')+'">'+esc(num(x.score))+'</b></div>').join(''):'<div class="empty">Значимых отклонений по подразделениям не выявлено.</div>')+'</section><section class="section"><h2>Ключевые направления</h2>'+dims.map(x=>'<div class="row"><span>'+esc(x.title)+'</span><b class="'+(x.score<55?'bad':x.score<70?'warn':'ok')+'">'+esc(num(x.score))+'</b></div>').join('')+'</section></div></div>';
 $('#content').innerHTML=html;$('#updated').textContent='Данные обновлены: '+new Date(d.generated_at||Date.now()).toLocaleString('ru-RU');
}
async function jsonFetch(url,options={},timeout=20000){const c=new AbortController(),timer=setTimeout(()=>c.abort(),timeout);try{const r=await fetch(url,{...options,signal:c.signal,cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.detail||('HTTP '+r.status));return d}finally{clearTimeout(timer)}}
async function loadLatest(){try{const d=await jsonFetch('/executive-intelligence/latest?_= '+Date.now(),{},5000);render(d);return true}catch(e){return false}}
async function refresh(background=false){try{if(!background){$('#refresh').disabled=true;$('#updated').textContent='Обновление данных в фоне…'}const d=await jsonFetch('/executive-intelligence/collect',{method:'POST'},30000);render(d);$('#notice').innerHTML=''}catch(e){$('#notice').innerHTML='<div class="notice">Не удалось обновить данные. Показан последний подтверждённый снимок. Причина: '+esc(e.name==='AbortError'?'превышено время ожидания':e.message)+'</div>'}finally{$('#refresh').disabled=false}}
async function boot(){const shown=await loadLatest();if(!shown){$('#content').innerHTML='<div class="section empty">Последний снимок отсутствует. Выполняется первичный расчёт…</div>';await refresh(false)}else{refresh(true)}}
async function history(){try{const rows=await jsonFetch('/management-reports',{},5000);$('#history').innerHTML=rows.length?rows.map(x=>'<tr><td>'+esc(new Date(x.generated_at).toLocaleString('ru-RU'))+'</td><td>'+(x.mode==='detailed'?'Подробный':'Краткий')+'</td><td><a class="btn" href="/management-reports/'+x.id+'/pdf">PDF</a></td></tr>').join(''):'<tr><td colspan="3" class="empty">Подробных отчётов пока нет.</td></tr>';if(rows[0])$('#latestPdf').href='/management-reports/'+rows[0].id+'/pdf'}catch(e){$('#history').innerHTML='<tr><td colspan="3">История временно недоступна.</td></tr>'}}
$('#refresh').onclick=()=>refresh(false);$('#generate').onclick=async()=>{try{$('#generate').disabled=true;$('#reportStatus').textContent='Формируется подробный отчёт…';const d=await jsonFetch('/management-reports/generate?mode=detailed',{method:'POST'},120000);$('#reportStatus').textContent='Подробный отчёт готов.';await history();window.open('/management-reports/'+d.id+'/pdf','_blank')}catch(e){$('#reportStatus').textContent='Ошибка: '+e.message}finally{$('#generate').disabled=false}};
boot();history();setInterval(()=>refresh(true),900000);
</script></body></html>'''
